35	const AuthServiceType string = "generic"
36	
37	// validate interface
38	var _ auth.AuthServiceConfig = Config{}
39	
40	// Auth service configuration
41	type Config struct {
42		Name                   string   `yaml:"name" validate:"required"`
43		Type                   string   `yaml:"type" validate:"required"`
44		Audience               string   `yaml:"audience" validate:"required"`
45		McpEnabled             bool     `yaml:"mcpEnabled"`
46		AuthorizationServer    string   `yaml:"authorizationServer" validate:"required"`
47		ScopesRequired         []string `yaml:"scopesRequired"`
48		IntrospectionEndpoint  string   `yaml:"introspectionEndpoint"`
49		IntrospectionMethod    string   `yaml:"introspectionMethod"`
50		IntrospectionParamName string   `yaml:"introspectionParamName"`
51	}
52	
53	// Returns the auth service type
54	func (cfg Config) AuthServiceConfigType() string {
55		return AuthServiceType
56	}
57	
58	// Initialize a generic auth service
59	func (cfg Config) Initialize() (auth.AuthService, error) {
60		if !cfg.McpEnabled {
61			if cfg.IntrospectionEndpoint != "" {
62				return nil, fmt.Errorf("`introspectionEndpoint` is not allowed when `mcpEnabled` is false")
63			}
64			if cfg.IntrospectionMethod != "" {
65				return nil, fmt.Errorf("`introspectionMethod` is not allowed when `mcpEnabled` is false")
66			}
67			if cfg.IntrospectionParamName != "" {
68				return nil, fmt.Errorf("`introspectionParamName` is not allowed when `mcpEnabled` is false")
69			}
70			if len(cfg.ScopesRequired) > 0 {
71				return nil, fmt.Errorf("`scopesRequired` is not allowed when `mcpEnabled` is false")
72			}
73		}
74		httpClient := newSecureHTTPClient()
75	
76		// Discover OIDC endpoints
77		jwksURL, introspectionURL, issuer, err := discoverOIDCConfig(httpClient, cfg.AuthorizationServer)
78		if err != nil {
79			return nil, fmt.Errorf("failed to discover OIDC config: %w", err)
80		}
81	
82		// Override introspection URL if configured
83		if cfg.IntrospectionEndpoint != "" {
84			introspectionURL = cfg.IntrospectionEndpoint
85		}
86	
87		// Create the keyfunc to fetch and cache the JWKS in the background
88		kf, err := keyfunc.NewDefault([]string{jwksURL})
89		if err != nil {
90			return nil, fmt.Errorf("failed to create keyfunc from JWKS URL %s: %w", jwksURL, err)
91		}
92	
93		a := &AuthService{
94			Config:           cfg,
95			kf:               kf,
96			client:           httpClient,
97			introspectionURL: introspectionURL,
98			issuer:           issuer,
99		}
100		return a, nil
101	}
102	
103	func newSecureHTTPClient() *http.Client {
104		return &http.Client{
105			Timeout: 10 * time.Second,
106			Transport: &http.Transport{
107				ForceAttemptHTTP2:     true,
108				MaxIdleConns:          10,
109				IdleConnTimeout:       90 * time.Second,
110				TLSHandshakeTimeout:   5 * time.Second,
111				ExpectContinueTimeout: 1 * time.Second,
112			},
113			CheckRedirect: func(req *http.Request, via []*http.Request) error {
114				return http.ErrUseLastResponse
115			},
116		}
117	}
118	
119	func discoverOIDCConfig(client *http.Client, AuthorizationServer string) (jwksURI string, introspectionEndpoint string, issuer string, err error) {
120		u, err := url.Parse(AuthorizationServer)
121		if err != nil {
122			return "", "", "", fmt.Errorf("invalid auth URL")
123		}
124		if u.Scheme != "https" {
125			log.Printf("WARNING: HTTP instead of HTTPS is being used for AuthorizationServer: %s", AuthorizationServer)
126		}
127	
128		oidcConfigURL, err := url.JoinPath(AuthorizationServer, ".well-known/openid-configuration")
129		if err != nil {
130			return "", "", "", err
131		}
132	
133		resp, err := client.Get(oidcConfigURL)
134		if err != nil {
135			return "", "", "", fmt.Errorf("failed to fetch OIDC config: %w", err)
136		}
137		defer resp.Body.Close()
138	
139		if resp.StatusCode != http.StatusOK {
140			return "", "", "", fmt.Errorf("unexpected status: %d", resp.StatusCode)
141		}
142	
143		// Limit read size to 1MB to prevent memory exhaustion
144		body, err := io.ReadAll(io.LimitReader(resp.Body, 1<<20))
145		if err != nil {
146			return "", "", "", err
147		}
148	
149		var config struct {
150			Issuer                string `json:"issuer"`
151			JwksUri               string `json:"jwks_uri"`
152			IntrospectionEndpoint string `json:"introspection_endpoint"`
153		}
154		if err := json.Unmarshal(body, &config); err != nil {
155			return "", "", "", err
156		}
157	
158		if config.JwksUri == "" {
159			return "", "", "", fmt.Errorf("jwks_uri not found in config")
160		}
161	
162		// Sanitize the resulting JWKS URI before returning it
163		parsedJWKS, err := url.Parse(config.JwksUri)
164		if err != nil {
165			return "", "", "", fmt.Errorf("invalid jwks_uri detected")
166		}
167		if parsedJWKS.Scheme != "https" {
168			log.Printf("WARNING: HTTP instead of HTTPS is being used for JWKS URI: %s", config.JwksUri)
169		}
170	
171		return config.JwksUri, config.IntrospectionEndpoint, config.Issuer, nil
172	}
