176	// struct used to store auth service info
177	type AuthService struct {
178		Config
179		kf               keyfunc.Keyfunc
180		client           *http.Client
181		introspectionURL string
182		issuer           string
183	}
184	
185	// Returns the auth service type
186	func (a AuthService) AuthServiceType() string {
187		return AuthServiceType
188	}
