211	// Verifies generic JWT access token inside the Authorization header
212	func (a AuthService) GetClaimsFromHeader(ctx context.Context, h http.Header) (map[string]any, error) {
213		if a.McpEnabled {
214			return nil, nil
215		}
216	
217		tokenString := h.Get(a.Name + "_token")
218		if tokenString == "" {
219			return nil, nil
220		}
221	
222		// Parse and verify the token signature
223		token, err := jwt.Parse(tokenString, a.kf.Keyfunc)
224		if err != nil {
225			return nil, fmt.Errorf("failed to parse and verify JWT token: %w", err)
226		}
227	
228		if !token.Valid {
229			return nil, fmt.Errorf("invalid JWT token")
230		}
231	
232		claims, ok := token.Claims.(jwt.MapClaims)
233		if !ok {
234			return nil, fmt.Errorf("invalid JWT claims format")
235		}
236	
237		// Validate 'aud' (audience) claim
238		aud, err := claims.GetAudience()
239		if err != nil {
240			return nil, fmt.Errorf("could not parse audience from token: %w", err)
241		}
242	
243		isAudValid := false
244		for _, audItem := range aud {
245			if audItem == a.Audience {
246				isAudValid = true
247				break
248			}
249		}
250	
251		if !isAudValid {
252			return nil, fmt.Errorf("audience validation failed: expected %s, got %v", a.Audience, aud)
253		}
254	
255		return claims, nil
256	}
257	
258	// MCPAuthError represents an error during MCP authentication validation.
259	type MCPAuthError = auth.MCPAuthError
260	
261	// ValidateMCPAuth handles MCP auth token validation
262	func (a AuthService) ValidateMCPAuth(ctx context.Context, h http.Header) (map[string]any, error) {
263		tokenString := h.Get("Authorization")
264		if tokenString == "" {
265			return nil, &MCPAuthError{Code: http.StatusUnauthorized, Message: "missing access token", ScopesRequired: a.ScopesRequired}
266		}
267	
268		headerParts := strings.Split(tokenString, " ")
269		if len(headerParts) != 2 || strings.ToLower(headerParts[0]) != "bearer" {
270			return nil, &MCPAuthError{Code: http.StatusUnauthorized, Message: "authorization header must be in the format 'Bearer <token>'", ScopesRequired: a.ScopesRequired}
271		}
272	
273		tokenStr := headerParts[1]
274	
275		if isJWTFormat(tokenStr) {
276			return a.validateJwtToken(ctx, tokenStr)
277		}
278		return a.validateOpaqueToken(ctx, tokenStr)
279	}
280	
281	func isJWTFormat(token string) bool {
282		parts := strings.Split(token, ".")
283		if len(parts) != 3 {
284			return false
285		}
286		headerBytes, err := base64.RawURLEncoding.DecodeString(parts[0])
287		if err != nil {
288			return false
289		}
290		var header map[string]any
291		if err := json.Unmarshal(headerBytes, &header); err != nil {
292			return false
293		}
294		_, hasAlg := header["alg"]
295		return hasAlg
296	}
297	
298	// validateJwtToken validates a JWT token locally
299	func (a AuthService) validateJwtToken(ctx context.Context, tokenStr string) (map[string]any, error) {
300		token, err := jwt.Parse(tokenStr, a.kf.Keyfunc)
301		if err != nil || !token.Valid {
302			return nil, &MCPAuthError{Code: http.StatusUnauthorized, Message: "invalid or expired token", ScopesRequired: a.ScopesRequired}
303		}
304	
305		claims, ok := token.Claims.(jwt.MapClaims)
306		if !ok {
307			return nil, &MCPAuthError{Code: http.StatusUnauthorized, Message: "invalid JWT claims format", ScopesRequired: a.ScopesRequired}
308		}
309	
310		// Validate issuer
311		iss, err := claims.GetIssuer()
312		if err != nil {
313			return nil, &MCPAuthError{Code: http.StatusUnauthorized, Message: "could not parse issuer from token", ScopesRequired: a.ScopesRequired}
314		}
315		if iss == "" {
316			return nil, &MCPAuthError{Code: http.StatusUnauthorized, Message: "missing issuer claim in token", ScopesRequired: a.ScopesRequired}
317		}
318	
319		// Validate audience
320		aud, err := claims.GetAudience()
321		if err != nil {
322			return nil, &MCPAuthError{Code: http.StatusUnauthorized, Message: "could not parse audience from token", ScopesRequired: a.ScopesRequired}
323		}
324	
325		scopeClaim, _ := claims["scope"].(string)
326	
327		err = a.validateClaims(ctx, iss, aud, scopeClaim)
328		if err != nil {
329			return nil, err
330		}
331		return claims, nil
332	}
333	
334	// validateOpaqueToken validates an opaque token by calling the introspection endpoint
335	func (a AuthService) validateOpaqueToken(ctx context.Context, tokenStr string) (map[string]any, error) {
336		logger, err := util.LoggerFromContext(ctx)
337		if err != nil {
338			return nil, fmt.Errorf("failed to get logger from context: %w", err)
339		}
340	
341		introspectionURL := a.introspectionURL
342		if introspectionURL == "" {
343			introspectionURL, err = url.JoinPath(a.AuthorizationServer, "introspect")
344			if err != nil {
345				return nil, fmt.Errorf("failed to construct introspection URL: %w", err)
346			}
347		}
348	
349		paramName := a.IntrospectionParamName
350		if paramName == "" {
351			paramName = "token"
352		}
353	
354		var req *http.Request
355		if a.IntrospectionMethod == "GET" {
356			u, err := url.Parse(introspectionURL)
357			if err != nil {
358				return nil, fmt.Errorf("failed to parse introspection URL: %w", err)
359			}
360			q := u.Query()
361			q.Set(paramName, tokenStr)
362			u.RawQuery = q.Encode()
363			req, err = http.NewRequestWithContext(ctx, "GET", u.String(), nil)
364			if err != nil {
365				return nil, fmt.Errorf("failed to create introspection request: %w", err)
366			}
367		} else {
368			data := url.Values{}
369			data.Set(paramName, tokenStr)
370			req, err = http.NewRequestWithContext(ctx, "POST", introspectionURL, strings.NewReader(data.Encode()))
371			if err != nil {
372				return nil, fmt.Errorf("failed to create introspection request: %w", err)
373			}
374			req.Header.Set("Content-Type", "application/x-www-form-urlencoded")
375		}
376		req.Header.Set("Accept", "application/json")
377	
378		// Send request to auth server's introspection endpoint
379		resp, err := a.client.Do(req)
380		if err != nil {
381			logger.ErrorContext(ctx, "failed to call introspection endpoint: %v", err)
382			return nil, &MCPAuthError{Code: http.StatusInternalServerError, Message: fmt.Sprintf("failed to call introspection endpoint: %v", err), ScopesRequired: a.ScopesRequired}
383		}
384		defer resp.Body.Close()
385	
386		if resp.StatusCode != http.StatusOK {
387			logger.WarnContext(ctx, "introspection failed with status: %d", resp.StatusCode)
388			return nil, &MCPAuthError{Code: http.StatusUnauthorized, Message: fmt.Sprintf("introspection failed with status: %d", resp.StatusCode), ScopesRequired: a.ScopesRequired}
389		}
390	
391		body, err := io.ReadAll(io.LimitReader(resp.Body, 1<<20))
392		if err != nil {
393			return nil, fmt.Errorf("failed to read introspection response: %w", err)
394		}
395	
396		var introspectResp struct {
397			Active   *bool           `json:"active"`
398			Scope    string          `json:"scope"`
399			Aud      json.RawMessage `json:"aud"`
400			Audience json.RawMessage `json:"audience"`
401			Exp      json.Number     `json:"exp"`
402			Iss      string          `json:"iss"`
403		}
404	
405		if err := json.Unmarshal(body, &introspectResp); err != nil {
406			return nil, fmt.Errorf("failed to parse introspection response: %w", err)
407		}
408	
409		if introspectResp.Active == nil || !*introspectResp.Active {
410			logger.InfoContext(ctx, "token is not active")
411			return nil, &MCPAuthError{Code: http.StatusUnauthorized, Message: "token is not active", ScopesRequired: a.ScopesRequired}
412		}
413	
414		var expVal int64
415		if introspectResp.Exp != "" {
416			expVal, err = introspectResp.Exp.Int64()
417			if err != nil {
418				logger.WarnContext(ctx, "failed to parse exp claim in introspection response: %v", err)
419				return nil, &MCPAuthError{Code: http.StatusUnauthorized, Message: "invalid exp claim", ScopesRequired: a.ScopesRequired}
420			}
421		}
422	
423		// Verify expiration (with 1 minute leeway)
424		const leeway = 60
425		if expVal > 0 && time.Now().Unix() > (expVal+leeway) {
426			logger.WarnContext(ctx, "token has expired: exp=%d, now=%d", expVal, time.Now().Unix())
427			return nil, &MCPAuthError{Code: http.StatusUnauthorized, Message: "token has expired", ScopesRequired: a.ScopesRequired}
428		}
429	
430		// Extract audience
431		// According to RFC 7662, the aud claim can be a string or an array of strings
432		// Fallback to "audience" for Google tokeninfo
433		audData := introspectResp.Aud
434		if len(audData) == 0 {
435			audData = introspectResp.Audience
436		}
437	
438		var aud []string
439		if len(audData) > 0 {
440			var audStr string
441			var audArr []string
442			if err := json.Unmarshal(audData, &audStr); err == nil {
443				aud = []string{audStr}
444			} else if err := json.Unmarshal(audData, &audArr); err == nil {
445				aud = audArr
446			} else {
447				logger.WarnContext(ctx, "failed to parse aud or audience claim in introspection response")
448				return nil, &MCPAuthError{Code: http.StatusUnauthorized, Message: "invalid aud claim", ScopesRequired: a.ScopesRequired}
449			}
450		}
451	
452		err = a.validateClaims(ctx, introspectResp.Iss, aud, introspectResp.Scope)
453		if err != nil {
454			return nil, err
455		}
456		claims := map[string]any{
457			"active": introspectResp.Active,
458			"scope":  introspectResp.Scope,
459			"aud":    aud,
460			"exp":    expVal,
461			"iss":    introspectResp.Iss,
462		}
463		return claims, nil
464	}
465	
466	// validateClaims validates the audience and scopes of a token
467	func (a AuthService) validateClaims(ctx context.Context, iss string, aud []string, scopeStr string) error {
468		logger, err := util.LoggerFromContext(ctx)
469		if err != nil {
470			return fmt.Errorf("failed to get logger from context: %w", err)
471		}
472	
473		// Validate issuer
474		if a.issuer != "" && iss != "" {
475			if iss != a.issuer {
476				logger.WarnContext(ctx, "issuer validation failed: expected %s, got %s", a.issuer, iss)
477				return &MCPAuthError{Code: http.StatusUnauthorized, Message: "issuer validation failed", ScopesRequired: a.ScopesRequired}
478			}
479		}
480	
481		// Validate audience
482		if a.Audience != "" {
483			isAudValid := false
484			for _, audItem := range aud {
485				if audItem == a.Audience {
486					isAudValid = true
487					break
488				}
489			}
490	
491			if !isAudValid {
492				logger.WarnContext(ctx, "audience validation failed: expected %s", a.Audience)
493				return &MCPAuthError{Code: http.StatusUnauthorized, Message: "audience validation failed", ScopesRequired: a.ScopesRequired}
494			}
495		}
496	
497		// Check scopes
498		if len(a.ScopesRequired) > 0 {
499			tokenScopes := strings.Fields(scopeStr)
500			scopeMap := make(map[string]bool)
501			for _, s := range tokenScopes {
502				scopeMap[s] = true
503			}
504	
505			for _, requiredScope := range a.ScopesRequired {
506				if !scopeMap[requiredScope] {
507					logger.WarnContext(ctx, "insufficient scopes: missing %s", requiredScope)
508					return &MCPAuthError{Code: http.StatusForbidden, Message: "insufficient scopes", ScopesRequired: a.ScopesRequired}
509				}
510			}
511		}
512	
513		return nil
514	}
